// Simulate three modules with shape area functions:
// circleArea(radius: number): number
// rectangleArea(width: number, height: number): number
// triangleArea(base: number, height: number): number

// Define all three functions, then use them
// Print the area of a circle with radius 5 (use Math.PI, round to 2 decimals)
// Print the area of a 4x6 rectangle
// Print the area of a triangle with base 3 and height 8

exercises.solution:
function circleArea(radius: number): number {
  return Math.PI * radius * radius;
}

function rectangleArea(width: number, height: number): number {
  return width * height;
}

function triangleArea(base: number, height: number): number {
  return (base * height) / 2;
}

console.log(Number(circleArea(5).toFixed(2)));
console.log(rectangleArea(4, 6));
console.log(triangleArea(3, 8));

