// Write a function resolveAlias(importPath: string, aliasMap: Record<string, string>): string
// The aliasMap keys use '@alias/*' pattern (with wildcard)
// Replace the alias prefix with the mapped path
// If no alias matches, return the original importPath

// Example aliasMap:
// { '@components/*': 'src/components/*', '@hooks/*': 'src/hooks/*' }

// Your code here

// const aliases = { '@components/*': 'src/components/*', '@hooks/*': 'src/hooks/*' };
// console.log(resolveAlias('@components/Button', aliases));
// console.log(resolveAlias('@hooks/useAuth', aliases));
// console.log(resolveAlias('./local', aliases));

exercises.solution:
function resolveAlias(importPath: string, aliasMap: Record<string, string>): string {
  for (const [pattern, target] of Object.entries(aliasMap)) {
    const prefix = pattern.replace('/*', '');
    const targetBase = target.replace('/*', '');
    if (importPath.startsWith(prefix)) {
      return importPath.replace(prefix, targetBase);
    }
  }
  return importPath;
}

const aliases = { '@components/*': 'src/components/*', '@hooks/*': 'src/hooks/*' };
console.log(resolveAlias('@components/Button', aliases));
console.log(resolveAlias('@hooks/useAuth', aliases));
console.log(resolveAlias('./local', aliases));

