// Define an interface 'StringUtils' with:
// capitalize(str: string): string - capitalizes first letter
// reverse(str: string): string - reverses the string
// truncate(str: string, maxLen: number): string - truncates with '...' if longer than maxLen

// Implement the object and test it:
// capitalize('hello world')
// reverse('TypeScript')
// truncate('This is a long sentence', 10)

// Your code here

exercises.solution:
interface StringUtils {
  capitalize(str: string): string;
  reverse(str: string): string;
  truncate(str: string, maxLen: number): string;
}

const stringUtils: StringUtils = {
  capitalize(str: string): string {
    return str.charAt(0).toUpperCase() + str.slice(1);
  },
  reverse(str: string): string {
    return str.split('').reverse().join('');
  },
  truncate(str: string, maxLen: number): string {
    if (str.length <= maxLen) return str;
    return str.slice(0, maxLen) + '...';
  }
};

console.log(stringUtils.capitalize('hello world'));
console.log(stringUtils.reverse('TypeScript'));
console.log(stringUtils.truncate('This is a long sentence', 10));

