// Create a PluginRegistry interface with:
// register(name: string, config: Record<string, any>): void
// get(name: string): Record<string, any> | undefined
// list(): string[]

// Implement it using a Map internally
// Register 'auth' with { provider: 'oauth', timeout: 5000 }
// Register 'cache' with { ttl: 3600, maxSize: 100 }
// Print list of registered plugins
// Print the auth plugin config's provider
// Print the cache plugin config's ttl

// Your code here

exercises.solution:
interface PluginRegistry {
  register(name: string, config: Record<string, any>): void;
  get(name: string): Record<string, any> | undefined;
  list(): string[];
}

const registry: PluginRegistry = (() => {
  const plugins = new Map<string, Record<string, any>>();
  return {
    register(name: string, config: Record<string, any>): void {
      plugins.set(name, config);
    },
    get(name: string): Record<string, any> | undefined {
      return plugins.get(name);
    },
    list(): string[] {
      return Array.from(plugins.keys());
    }
  };
})();

registry.register('auth', { provider: 'oauth', timeout: 5000 });
registry.register('cache', { ttl: 3600, maxSize: 100 });
console.log(registry.list().join(', '));
console.log(registry.get('auth')!.provider);
console.log(registry.get('cache')!.ttl);
